Location: crates/dspy-rs/src/adapter/chat.rs

Replace the stubs with real implementation:

```rust
impl ChatAdapter {
    pub fn format_system_message<S: Signature>(&self) -> Result<String, RenderError> {
        let compiled = S::compile();
        // For system message, we don't need real input - use Default or empty
        let dummy_input = S::Input::default();  // or build minimal
        compiled.render_messages(&dummy_input)
            .map(|m| m.system)
    }

    pub fn format_user_message<S: Signature>(&self, input: &S::Input) -> Result<String, RenderError> {
        let compiled = S::compile();
        compiled.render_messages(input)
            .map(|m| m.user)
    }

    pub fn format_demo<S: Signature>(&self, demo: &S) -> Result<(String, String), RenderError> {
        let compiled = S::compile();
        let user = compiled.render_messages(demo.input())?.user;
        // Output rendering for demo...
        let output = self.format_output::<S>(demo.output())?;
        Ok((user, output))
    }
}
```

